def solve(challenges):
    if not challenges:
        return []

    results = []
    for challenge in challenges:
        if 'id' in challenge and 'status' in challenge:
            results.append({
                'id': challenge['id'],
                'status': challenge['status'],
                'phase': challenge.get('phase', 'unknown')
            })
    return results
